{{- else }}
existingToken: ""
{{- end }}

{{- $s := lookup "v1" "Secret" .Release.Namespace (printf "%s-auth" .Release.Name) -}}
{{- if $s -}}
password: {{ index $s.data "password" }}
{{- else -}}
password: {{ randAlphaNum 32 | b64enc | quote }}
{{- end -}}

metadata:
